        List<List<Integer>> result = new ArrayList<>();
        Arrays.sort(candidates);
        backtrack(candidates, 0, new ArrayList<>(), target, result);
        return result;
    }
    private void backtrack(int[] candidates, int start, List<Integer> current, int remaining, List<List<Integer>> result) {
        if (remaining == 0) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = start; i < candidates.length; i++) {
            if (candidates[i] > remaining) break;
            current.add(candidates[i]);
            backtrack(candidates, i, current, remaining - candidates[i], result);
            current.remove(current.size() - 1);
        }
    }
}

